const express = require('express')
let port = process.env.PORT || 3001; let app = express()
app.use(express.json())
const Elasticsearch = require("elasticsearch"); const client = new Elasticsearch({ hosts: ["http://localhost:9200"] })
app.listen(port)

// Create a endpoint for the index names - /indices/
app.get('/indices', async (req,res)=>{try{ const response = await client.cat.indices(); res.json(response);} catch(error){ console.log('Error - ',error); res.status(501).send("Error");} })